/**
 * Record emitter — in-process fan-out of every `PersistedRecord` the
 * host persists to its run log.  spec: `docs/record-emitter-spec.md` §3, §4.
 *
 * **Scoping** (record-emitter-spec §4.1): this emitter covers the
 * loop-time `host.persistRecord` call-site only — both
 * `ProductionHost.persistRecord` and `StubHost.persistRecord` call
 * `notifyListeners` after `log.append`.  Direct `log.append` calls
 * elsewhere in `src/host/` (e.g. the four call-sites in
 * `src/host/api.ts` for initial snapshot, crash reconciliation,
 * session_failed("crashed"), and the crash snapshot) are outside the
 * emitter's scope — they bypass `persistRecord` and therefore do not
 * fire listeners.  The durable JSONL log remains the system of
 * record; the emitter is best-effort delivery on top.
 *
 * ## Module-level design
 *
 * - **Process-global registry.**  One `Set<Listener>` for the entire
 *   pi process.  A consumer extension subscribes once (at extension
 *   load) and receives records from all hosts in the process.  If
 *   per-host isolation is needed in the future, it's an additive
 *   change (host-scoped registry); v1 is process-global.
 * - **Thread-safety.**  Node.js is single-threaded; the `Set` is
 *   safe to read and mutate from the same event-loop turn.
 *   Listeners are fire-and-forget (§4.3) — the host does not `await`
 *   async listeners, so there is no concurrent mutation risk from
 *   interleaved promises.
 * - **Zero I/O, zero pi imports.**  This module is pure in-process
 *   fan-out; it lives in `src/host/` (which the grep-guard allows to
 *   import pi, but this module doesn't need to).
 */

import type { PersistedRecord } from "../persistence/log.js";

/**
 * A listener callback for `subscribeToRecords`.
 *
 * May be sync or async.  The host fires listeners fire-and-forget —
 * async listeners are NOT awaited (§4.3).
 */
export type Listener = (record: PersistedRecord) => void | Promise<void>;

/**
 * Module-level listener registry.
 *
 * `Set` preserves insertion order per the ES2015 spec, giving FIFO
 * delivery (§4.2).  Re-entrant mutations (subscribe / unsubscribe
 * inside a listener) are handled by snapshotting the set before
 * iteration (§4.5).
 */
const listeners = new Set<Listener>();

/**
 * Subscribe to every record the host driver persists to a run log.
 *
 * Listeners fire in subscription order (FIFO).  Each listener is
 * invoked exactly once per record the host persists.  Listener
 * errors are isolated: a sync throw or async rejection in one
 * listener does not affect the engine or other listeners (§4).
 *
 * Returns an unsubscribe handle.  Calling the handle a second time
 * is a no-op.  The listener is removed from the registry on the
 * first call; subsequent calls return without effect.
 *
 * Listeners may be sync or async.  The host fires listeners
 * fire-and-forget — async listeners are NOT awaited (§4.3).
 *
 * Re-entrant subscribe / unsubscribe from inside a listener is
 * permitted: subscriptions made inside a listener fire on the
 * NEXT record, not the current one; unsubscribes made inside a
 * listener take effect on the next record.  The current record's
 * dispatch is unaffected (§4.5).
 *
 * @param listener  Callback invoked for every persisted record.
 * @returns         An idempotent unsubscribe function.
 */
export function subscribeToRecords(listener: Listener): () => void {
  listeners.add(listener);
  let called = false;
  return () => {
    if (called) return;
    called = true;
    listeners.delete(listener);
  };
}

/**
 * Fan out a record to all registered listeners.
 *
 * Takes a snapshot of the listener set before iterating so
 * re-entrant mutations (subscribe / unsubscribe inside a listener)
 * don't affect the current dispatch (§4.5).  New subscriptions fire
 * on the next record; unsubscribes take effect on the next record.
 *
 * Sync throws are caught; async rejections are caught via `.catch()`.
 * Neither affects the engine or other listeners (§4.4).
 *
 * Fast-path: no-op when the set is empty.
 *
 * Fire-and-forget: async listeners are NOT awaited (§4.3).
 *
 * This is exported as an internal seam for the host implementations
 * (`ProductionHost.persistRecord`, `StubHost.persistRecord`).  It
 * is NOT re-exported from the public barrel — it's host-internal.
 */
export function notifyListeners(record: PersistedRecord): void {
  if (listeners.size === 0) return;
  // Snapshot to handle re-entrant mutations (§4.5).
  const snapshot = [...listeners];
  for (const listener of snapshot) {
    try {
      const result = listener(record);
      // Attach a .catch for async rejections — fire-and-forget
      // means we don't await, but we do suppress rejections (§4.4).
      if (
        result !== undefined &&
        typeof result === "object" &&
        typeof (result as Promise<void>).catch === "function"
      ) {
        (result as Promise<void>).catch(() => {
          // Silently suppress — error isolation §4.4.
          // Future: wire structured logging here (out of scope
          // under this spec; the host's observability seam is a
          // separate concern).
        });
      }
    } catch {
      // Silently suppress sync throws — error isolation §4.4.
    }
  }
}

/**
 * `PersistedRecord` union and the `RecordLog` interface — spec §11.1–§11.5.
 *
 * Every record the host appends to its `run_id`-keyed append-only log is
 * a member of `PersistedRecord`. The union covers:
 *
 *  - §11.2 `transition_accepted`
 *  - §11.3 `transition_rejected`
 *  - §11.4 `session_started` / `session_ended` / `session_failed`
 *  - §11.5 `model_fallback`
 *  - §11.1 `checkpoint_snapshot` (the wrapper around the full `Checkpoint`
 *    the host appends after every accepted/rejected transition so
 *    `latestCheckpoint(runId)` is a read of the last snapshot, not an
 *    event-sourced replay — §11.1 explicitly forbids replay).
 *
 * **`RecordLog`** is the host-side persistence contract. The pure core
 * ships the interface and an in-memory implementation for unit tests.
 * The Phase 4 host driver owns the file-backed implementation
 * (append-only JSONL keyed by `run_id`; no SDK branch scoping, §11.1).
 *
 * Host-agnostic. No pi imports, no real I/O.
 */

import type {
  Checkpoint,
  ModelFallback,
  SessionLifecycleEvent,
  TransitionAccepted,
  TransitionRejected,
} from "../core/types.js";

/**
 * §11.1: a checkpoint snapshot is a full Checkpoint, snapshotted after
 * every accepted/rejected transition (and on lifecycle changes that
 * affect `active_role_session`). The host appends it to its log; resume
 * reads the latest snapshot — never replays records.
 */
export interface CheckpointSnapshot {
  readonly type: "checkpoint_snapshot";
  readonly checkpoint: Checkpoint;
}

/** Union of every record the host appends to its run_id-keyed log. */
export type PersistedRecord =
  | TransitionAccepted
  | TransitionRejected
  | SessionLifecycleEvent
  | ModelFallback
  | CheckpointSnapshot;

// ─── RecordLog interface ───────────────────────────────────────────────

/**
 * Persistence contract for the host's run_id-keyed append-only log.
 *
 * `latestCheckpoint(runId)` reads the most recent `CheckpointSnapshot`
 * for the run. It does NOT scan or replay all records (§11.1: "the
 * snapshot *is* the state"). A snapshot taken with a non-null
 * `active_role_session` whose session never reached a terminal
 * lifecycle record is treated by the host as a crash mid-session
 * (§11.1: the host records a `session_failed("crashed")` for that
 * session before re-entering the loop).
 */
export interface RecordLog {
  /**
   * Append a single record. Append-only: implementations MUST NOT
   * mutate or remove previously-appended records. Order is preserved
   * within a single `run_id`.
   */
  append(record: PersistedRecord): void;

  /**
   * The latest `CheckpointSnapshot.checkpoint` for the run, or `null`
   * if no snapshot has been appended yet (run not started).
   */
  latestCheckpoint(runId: string): Checkpoint | null;

  /**
   * All records for the run in append order. The Phase 4 host may use
   * this for `runStats()` (§11.8) and roll-up queries; the pure core
   * uses it for `rollup` (§11.6) and `buildRunMemory` (§8.4).
   */
  records(runId: string): readonly PersistedRecord[];

  /**
   * The set of `run_id`s known to this log. Used by the Phase 4
   * `listRuns()` (§11.9) entry point; the pure core does not call it.
   */
  listRunIds(): readonly string[];

  /**
   * Release any underlying resources (file handles, etc.). The in-memory
   * implementation is a no-op. The Phase 4 file-backed impl MUST close
   * its file descriptor here.
   */
  close(): void;
}

// ─── InMemoryRecordLog ──────────────────────────────────────────────────

/**
 * Pure, in-memory `RecordLog` for unit tests. The Phase 4 host owns
 * the real file-backed implementation; this one is the test double
 * (and the model the host impl should match — same semantics, same
 * interface).
 *
 * Append-only: `append` only adds; `records` returns a frozen view.
 * `latestCheckpoint` walks `records` in reverse to find the last
 * `CheckpointSnapshot` for the run. This is the host-side pattern,
 * not a violation of the "no event-sourced replay" rule (replay
 * reconstructs from events without snapshots; here we have snapshots
 * and just want the last one).
 */
export class InMemoryRecordLog implements RecordLog {
  // Maps run_id -> records (in append order). Immutable from the
  // outside: the outer Map is replaced on each append so a snapshot
  // view returned by `records()` cannot change under the caller.
  private byRun: Map<string, PersistedRecord[]> = new Map();

  append(record: PersistedRecord): void {
    // CheckpointSnapshot does not carry its own `run_id` field — the
    // wrapped Checkpoint is the source of truth for which run the
    // snapshot belongs to. Every other record shape carries `run_id`
    // directly. Routing both through one branch keeps the persistence
    // contract uniform: a snapshot is appended under its checkpoint's
    // run_id.
    const runId = record.type === "checkpoint_snapshot" ? record.checkpoint.run_id : record.run_id;
    const list = this.byRun.get(runId);
    const next = list === undefined ? [record] : [...list, record];
    this.byRun.set(runId, next);
  }

  latestCheckpoint(runId: string): Checkpoint | null {
    const list = this.byRun.get(runId);
    if (list === undefined) return null;
    // Walk in reverse: most recent snapshot first.
    for (let i = list.length - 1; i >= 0; i--) {
      const record = list[i];
      if (record && record.type === "checkpoint_snapshot") {
        return record.checkpoint;
      }
    }
    return null;
  }

  records(runId: string): readonly PersistedRecord[] {
    const list = this.byRun.get(runId);
    if (list === undefined) return Object.freeze([]);
    return Object.freeze([...list]);
  }

  listRunIds(): readonly string[] {
    return Object.freeze([...this.byRun.keys()]);
  }

  close(): void {
    // No-op for in-memory. Phase 4 file-backed impl closes its FD here.
    this.byRun = new Map();
  }
}

/**
 * Run-lifecycle entry points — spec §11.1, §11.9, plan Task 13.5.
 *
 * Three top-level functions:
 *
 *  - `startRun(manifestPath, opts)` — load the manifest, mint a
 *    `run_id`, open the file-backed log, persist the initial
 *    `CheckpointSnapshot`, and enter the orchestration loop.
 *    Returns a `RunHandle` whose `completion()` resolves with the
 *    final checkpoint + exit reason.
 *
 *  - `resumeRun(manifestPath, runId, opts)` — re-load the manifest
 *    (def source), read the latest `CheckpointSnapshot` for
 *    `runId`, reconcile a crash-mid-session
 *    (`active_role_session` with no terminal lifecycle record →
 *    `session_failed("crashed")` for it), then re-enter the
 *    orchestration loop at `current_role`.
 *
 *  - `listRuns(baseDir)` — enumerate the `run_id`s known to the
 *    file log (for a future TUI viewer; spec §11.9).
 *
 * ## Host construction
 *
 * `startRun` and `resumeRun` accept a `hostFactory` callback that
 * builds the `Host` for the run. The factory receives the run's
 * `runId`, log, and def so it can wire everything before the loop
 * begins. Tests pass a `StubHost` factory (Task 16); production
 * passes an SDK-backed `Host` factory (Task 15's sibling, not yet
 * built).
 *
 * ## Crash reconciliation
 *
 * Per §11.1: "A snapshot whose `active_role_session` references a
 * session that never reached a terminal lifecycle record is
 * treated as a crash mid-session." The reconciler:
 *
 *   1. Finds the `session_started` record for the active session
 *      by `session_file`.
 *   2. If no `session_ended` or `session_failed` follows it,
 *      records `session_failed("crashed")` via `reduceLifecycle`
 *      (clearing `active_role_session`).
 *   3. Persists a fresh `CheckpointSnapshot` reflecting the
 *      cleared session.
 *   4. The loop then resumes from `current_role` with a fresh
 *      `active_role_session = null`.
 *
 * ## Why the reducer is unchanged
 *
 * The reconciler calls `reduceLifecycle(session_failed, …)` —
 * the same path the loop uses for contract breaches (Task 15).
 * The reducer doesn't know about crash reconciliation; it sees a
 * `session_failed` lifecycle event and produces the canonical
 * record + checkpoint transition.
 */

import { mkdtemp } from "node:fs/promises";
import { tmpdir } from "node:os";
import { join } from "node:path";

import { createInitialCheckpoint } from "../core/reduce.js";
import { reduceLifecycle } from "../core/reduce-lifecycle.js";
import type { Checkpoint, MachineDefinition, Role, SessionLifecycleEvent } from "../core/types.js";
import { DEFAULT_MODEL_EFFORT } from "../core/types.js";
import type { CheckpointSnapshot, RecordLog } from "../persistence/log.js";
import type { Host, RoleSession } from "./host.js";
import { FileRecordLog } from "./log-file.js";
import { runLoop } from "./loop.js";
import { type LoadedManifest, loadManifest } from "./manifest.js";
import { type ConfigOverrideContainer, RunHandle } from "./run-handle.js";

// ─── Public types ──────────────────────────────────────────────────────

/** Top-level options for `startRun`. */
export interface StartRunOptions {
  /** Initial goal text seeded into the first orchestrator session. */
  readonly goal: string;
  /** Directory for the run log files. Defaults to a fresh `mkdtemp`. */
  readonly baseDir?: string;
  /**
   * Factory for the run's `Host`. Receives the run's `runId`, log,
   * manifest, and def. The factory is called once per `startRun` /
   * `resumeRun`; the host is NOT reused across resumes.
   */
  readonly hostFactory: (ctx: HostFactoryContext) => Host;
}

/** Top-level options for `resumeRun`. */
export interface ResumeRunOptions {
  /** Directory for the run log files. Must match the original `startRun`. */
  readonly baseDir?: string;
  /** Goal text for any resumed orchestrator session. */
  readonly goal: string;
  readonly hostFactory: (ctx: HostFactoryContext) => Host;
}

/** Context passed to the host factory on each run start / resume. */
export interface HostFactoryContext {
  readonly runId: string;
  readonly def: MachineDefinition;
  readonly log: RecordLog;
  /**
   * The loaded manifest the host reads role config from (Task 17 /
   * Task 18). Carries `def` and the parsed `Manifest` (so the host
   * can look up `role.max_session_cost_usd` and `role.models[]`).
   * The reducer never sees this — it is host-side state for
   * per-role cost caps and model fallback.
   */
  readonly loadedManifest: LoadedManifest;
}

// ─── startRun ──────────────────────────────────────────────────────────

/**
 * Start a new run. Loads the manifest, mints a `run_id`, opens the
 * file-backed log, persists the initial checkpoint snapshot, and
 * enters the orchestration loop.
 */
export async function startRun(manifestPath: string, opts: StartRunOptions): Promise<RunHandle> {
  const loaded = await loadManifest(manifestPath);
  const baseDir = await resolveBaseDir(opts.baseDir);
  const log = new FileRecordLog({ baseDir });
  const def = loaded.def;
  const initialCheckpoint = createInitialCheckpoint(def);
  const runId = initialCheckpoint.run_id;

  // Persist the initial checkpoint snapshot (§11.1: each transition
  // produces a new full snapshot).
  const initialSnapshot: CheckpointSnapshot = {
    type: "checkpoint_snapshot",
    checkpoint: initialCheckpoint,
  };
  log.append(initialSnapshot);

  const host = opts.hostFactory({ runId, def, log, loadedManifest: loaded });
  void opts.goal; // goal is unused by runLoop directly; Task 16.5 wires it into the orchestrator seed

  return await runWithCompletion({
    runId,
    def,
    log,
    host,
    initialCheckpoint,
    goal: opts.goal,
    loadedManifest: loaded,
  });
}

// ─── resumeRun ─────────────────────────────────────────────────────────

/**
 * Resume a previously-started run from the latest snapshot.
 *
 * Re-loads the manifest (the source of truth for `def`), verifies
 * its `manifest_version` matches the snapshot's pinned version,
 * reconciles a crash-mid-session if any, and re-enters the
 * orchestration loop at `current_role`.
 */
export async function resumeRun(
  manifestPath: string,
  runId: string,
  opts: ResumeRunOptions,
): Promise<RunHandle> {
  const baseDir = await resolveBaseDir(opts.baseDir);
  const log = new FileRecordLog({ baseDir });

  const checkpoint = log.latestCheckpoint(runId);
  if (checkpoint === null) {
    throw new Error(`resumeRun: no checkpoint_snapshot found for run_id '${runId}' in ${baseDir}`);
  }

  // Re-load the manifest from disk and verify the version pin.
  // The snapshot's manifest_version is the canonical link to the
  // manifest that was active when the run started; a mismatch
  // means the manifest was edited mid-run, which §10 forbids.
  const loaded = await loadManifest(manifestPath);
  if (loaded.def.manifest_version !== checkpoint.manifest_version) {
    throw new Error(
      `resumeRun: manifest_version mismatch — snapshot pinned '${checkpoint.manifest_version}', manifest at '${manifestPath}' is '${loaded.def.manifest_version}' (§10)`,
    );
  }
  const def = loaded.def;

  // Crash reconciliation (§11.1).
  const reconciledCheckpoint = reconcileCrash(runId, checkpoint, def, log);

  const host = opts.hostFactory({ runId, def, log, loadedManifest: loaded });
  void opts.goal;

  return await runWithCompletion({
    runId,
    def,
    log,
    host,
    initialCheckpoint: reconciledCheckpoint,
    goal: opts.goal,
    loadedManifest: loaded,
  });
}

// ─── listRuns ──────────────────────────────────────────────────────────

/** Enumerate the `run_id`s known to a file-backed log directory. */
export function listRuns(baseDir: string): readonly string[] {
  const log = new FileRecordLog({ baseDir });
  return log.listRunIds();
}

// ─── Internals ──────────────────────────────────────────────────────────

interface RunWithCompletionArgs {
  readonly runId: string;
  readonly def: MachineDefinition;
  readonly log: RecordLog;
  readonly host: Host;
  readonly initialCheckpoint: Checkpoint;
  readonly goal: string;
  readonly loadedManifest: LoadedManifest;
}

async function runWithCompletion(args: RunWithCompletionArgs): Promise<RunHandle> {
  const { runId, def, log, host, initialCheckpoint, goal, loadedManifest } = args;
  // Task 19: shared mutable container for the live `configOverride`.
  // The loop's `getRunCostCap` closure (below) reads from this
  // container; `RunHandle.runConfig` writes to it. Both must see
  // the same reference — closures capture by reference, and a
  // plain `RunConfigOverride` field on the handle would not be
  // visible to the closure. The container pattern is the simplest
  // way to share mutable host state between the handle and the
  // loop's run-cap check.
  const configOverrideContainer: ConfigOverrideContainer = { current: {} };

  // `getRunCostCap` is the loop's source of truth for the active
  // run cap. Precedence:
  //   1. `RunHandle.runConfig` override (set via `runConfig()`).
  //   2. Manifest's orchestrator `max_run_cost_usd` (the static
  //      default; §8.1).
  //   3. `null` — uncapped.
  // The closure reads `configOverrideContainer.current` on every
  // call, so a `runConfig` update is visible to the loop on its
  // next terminal usage capture.
  const getRunCostCap = (): number | null => {
    const override = configOverrideContainer.current.maxRunCostUsd;
    if (override !== undefined) return override;
    const orchestratorConfig = loadedManifest.manifest.roles.find(
      (r) => r.name === def.orchestrator,
    );
    return orchestratorConfig?.max_run_cost_usd ?? null;
  };

  // The initial orchestrator session is seeded with `goal` via the
  // runLoop's initialGoal parameter. Task 16.5 replaces this with a
  // per-turn run-memory injection.
  let activeSession: RoleSession | null = null;
  let pendingAbortReason: string | null = null;
  let abortRequested = false;
  const abortControl = {
    async setActiveSession(session: RoleSession | null): Promise<void> {
      activeSession = session;
      if (session === null) return;
      if (!abortRequested || pendingAbortReason === null) return;
      await host.abortSession(session, pendingAbortReason);
    },
    async requestAbort(reason: string): Promise<void> {
      if (abortRequested) return;
      abortRequested = true;
      pendingAbortReason = reason;
      if (activeSession === null) return;
      await host.abortSession(activeSession, reason);
    },
  };

  const completionPromise = runLoop({
    def,
    initialCheckpoint,
    host,
    initialGoal: goal,
    getRunCostCap,
    abortControl,
  });
  return new RunHandle({
    runId,
    def,
    log,
    configOverrideContainer,
    requestAbort: abortControl.requestAbort,
    completionPromise: completionPromise.then((r) => ({
      finalCheckpoint: r.finalCheckpoint,
      exitReason: r.exitReason,
    })),
  });
}

/**
 * Detect a crash-mid-session and reconcile via
 * `session_failed("crashed")` + cleared checkpoint. Returns the
 * checkpoint the loop should resume from.
 */
function reconcileCrash(
  runId: string,
  checkpoint: Checkpoint,
  def: MachineDefinition,
  log: RecordLog,
): Checkpoint {
  const active = checkpoint.active_role_session;
  if (active === null) return checkpoint;

  const records = log.records(runId);
  const sessionFile = active.session_file;

  // Find the session_started record for this session_file.
  let sessionStarted: SessionLifecycleEvent | null = null;
  for (const r of records) {
    if (r.type === "session_started" && r.session_file === sessionFile) {
      sessionStarted = r;
      break;
    }
  }
  if (sessionStarted === null) {
    // No matching session_started — defensive. Return as-is.
    return checkpoint;
  }

  // Has a terminal lifecycle record already been written for this session?
  let hasTerminal = false;
  for (const r of records) {
    if (
      (r.type === "session_ended" || r.type === "session_failed") &&
      r.session_file === sessionFile
    ) {
      hasTerminal = true;
      break;
    }
  }
  if (hasTerminal) {
    // Already reconciled (or another resume already did this). Just
    // ensure the checkpoint's active_role_session is cleared.
    if (checkpoint.active_role_session !== null) {
      const cleared: Checkpoint = {
        ...checkpoint,
        active_role_session: null,
        updated_at: Date.now(),
      };
      log.append({ type: "checkpoint_snapshot", checkpoint: cleared });
      return cleared;
    }
    return checkpoint;
  }

  // No terminal → crashed. Record session_failed("crashed") via the
  // reducer. The reducer validates identity (meta.sessionId must
  // match active_role_session.id) and produces the canonical
  // record + checkpoint transition.
  //
  // §11.4: terminals cost — both session_ended and session_failed
  // carry `usage`. For a crashed session, the per-session usage is
  // unknown (the loop never reached a terminal); the reconciler
  // records zeros. The actual usage, if recoverable, would have to
  // come from a partial event-stream aggregation; that's a Phase 5
  // enhancement. The §11.6 roll-up treats this as zeros for the
  // crashed session, which is the conservative interpretation (we
  // don't know how much was spent).
  const ts = Date.now();
  const result = reduceLifecycle(checkpoint, "session_failed", def, {
    role: active.role,
    sessionId: active.id,
    sessionFile: active.session_file,
    failureReason: "crashed",
    ts,
    visit_index: sessionStarted.visit_index,
    parent_session: sessionStarted.parent_session,
    usage: { input: 0, output: 0, cache_read: 0, cache_write: 0, tokens: 0, cost: 0 },
    model: sessionStarted.model,
    model_effort: sessionStarted.model_effort ?? DEFAULT_MODEL_EFFORT,
  });
  log.append(result.record);
  // Persist the cleared checkpoint.
  const snapshot: CheckpointSnapshot = {
    type: "checkpoint_snapshot",
    checkpoint: result.checkpoint,
  };
  log.append(snapshot);
  return result.checkpoint;
}

async function resolveBaseDir(baseDir: string | undefined): Promise<string> {
  if (baseDir !== undefined) return baseDir;
  return mkdtemp(join(tmpdir(), "pi-conductor-run-"));
}

